/**
 * IFC STEP 한 줄 스캔 시 IfcProduct 계열로 볼 타입명 (누락 시 추가).
 */
const RAW = `
IFCANNOTATION IFCBEAM IFCBEAMSTANDARDCASE IFCBOREHOLE IFCBRIDGE IFCBRIDGEPART IFCBUILDING
IFCBUILDINGELEMENTPART IFCBUILDINGELEMENTPROXY IFCBUILDINGSTOREY IFCCAISSONFOUNDATION
IFCCHIMNEY IFCCOLUMN IFCCOLUMNSTANDARDCASE IFCCOVERING IFCCURTAINWALL IFCDEEPFOUNDATION
IFCDISCRETEACCESSORY IFCDISTRIBUTIONCHAMBERELEMENT IFCDISTRIBUTIONCONTROLELEMENT
IFCDISTRIBUTIONELEMENT IFCDISTRIBUTIONFLOWELEMENT IFCDOOR IFCDOORSTANDARDCASE IFCEARTHWORKSELEMENT
IFCELEMENTASSEMBLY IFCENERGYCONVERSIONDEVICE IFCENGINE IFCEVCHARGER IFCEVAPORATIVECOOLER
IFCEXTERNALSPATIALELEMENT IFCFACILITY IFCFACILITYPART IFCFAN IFCFILTER IFCFLOWCONTROLLER
IFCFLOWFITTING IFCFLOWINSTRUMENT IFCFLOWMETER IFCFLOWMOVINGDEVICE IFCFLOWSEGMENT
IFCFLOWTERMINAL IFCTANK IFCFOOTING IFCGRID IFCHEATEXCHANGER IFCHUMIDIFIER IFCINTERCEPTOR
IFCJUNCTION IFCJUNCTIONBOX IFCLIGHTFIXTURE IFCLIGHTSOURCE IFCMEMBER IFCMEMBERSTANDARDCASE
IFCMOTORCONNECTION IFCOPENINGELEMENT IFCOUTLET IFCPAVEMENT IFCPILE IFCPIPE IFCPIPEFITTING
IFCPIPESEGMENT IFCPLATE IFCPLATESTANDARDCASE IFCPLATESTACK IFCPUMP IFCRAILING IFCRAILWAY
IFCRAILWAYPART IFCRAMP IFCRAMPFLIGHT IFCREINFORCEDSOIL IFCREINFORCINGBAR IFCREINFORCINGMESH
IFCROOF IFCSANITARYTERMINAL IFCSHADINGDEVICE IFCSITE IFCSLAB IFCSLABELEMENTEDCASE
IFCSLABSTANDARDCASE IFCSOLARDEVICE IFCSPACE IFCSTACKTERMINAL IFCSTAIR IFCSTAIRFLIGHT
IFCSTRUCTURALCURVECONNECTION IFCSTRUCTURALCURVEMEMBER IFCSTRUCTURALSURFACEMEMBER
IFCSURFACEFEATURE IFCSWITCHINGDEVICE IFCSYSTEMFURNITUREELEMENT IFCTENDON IFCTENDONANCHOR
IFCTRACKELEMENT IFCTRACKSTRUCTURE IFCTRANSFORMER IFCTUBEBUNDLE IFCUNITARYCONTROLELEMENT
IFCUNITARYEQUIPMENT IFCVALVE IFCVEHICLE IFCVIBRATIONDAMPER IFCVIBRATIONISOLATOR
IFCVOIDINGFEATURE IFCWALL IFCWALLELEMENTEDCASE IFCWALLSTANDARDCASE IFCWASTETERMINAL
IFCWINDOW IFCWINDOWSTANDARDCASE IFCWORKSURFACE IFCZONE IFCMOORINGDEVICE IFCGEOGRAPHICELEMENT
IFCGEOTECHNICALASSEMBLY IFCGEOTECHNICALELEMENT IFCKERB IFCLINEARELEMENT IFCMARINEFACILITY
IFCMARINEPART IFCPROJECTIONELEMENT IFCROAD IFCROADPART IFCSIGN IFCTUNNEL IFCTUNNELPART
IFCFASTENER IFCMECHANICALFASTENER IFCCIVILELEMENT IFCNAVIGATIONALELEMENT
IFCWALLTYPE IFCSLABTYPE IFCBEAMTYPE IFCCOLUMNTYPE IFCDOORTYPE IFCWINDOWTYPE IFCMEMBERTYPE
IFCPLATETYPE IFCRAILINGTYPE IFCRAMPTYPE IFCROOFTYPE IFCSTAIRTYPE
`
  .trim()
  .split(/\s+/)
  .filter(Boolean)

const IFC_PRODUCT_TYPES = new Set(RAW)

function isIfcProductType(typeName) {
  return IFC_PRODUCT_TYPES.has(String(typeName || '').toUpperCase())
}

module.exports = { isIfcProductType, IFC_PRODUCT_TYPES }
